    var i := LeftmostEmpty(rooms);
    if i == -1 then rooms else rooms[i := 1]
  else if event == 'R' then
    var i := RightmostEmpty(rooms);
    if i == -1 then rooms else rooms[i := 1]
  else if '0' <= event <= '9' then
    rooms[(event as int) - ('0' as int) := 0]
  else
    rooms
}

