          rooms := rooms[i := 1];
          found := true;
        } else {
          i := i - 1;
        }
      }
      if !found {
        RightmostEmptyNone(old_rooms);
      }
    } else if '0' <= ch <= '9' {
      var i := (ch as int) - ('0' as int);
      rooms := rooms[i := 0];
    }
    assert rooms == HotelAfterEvent(old_rooms, ch);

    idx := idx + 1;
  }

  // Add assertion to check final state
  assert rooms == HotelAfterEvents(events);
  return rooms;
}
